/**
 * Netflix-style image avatars.
 *
 * Each avatar is a deterministic illustrated character portrait
 * generated by DiceBear (MIT-licensed, free, no API key required —
 * https://www.dicebear.com).  We ship eleven categories spanning
 * Anime, Realistic People, Cartoon Faces, Sci-Fi Robots, Pixel
 * Art, etc.  The PNG endpoint is used (over SVG) so the older
 * Chrome 52 WebView on HK1 boxes renders the tiles reliably.
 *
 * Each tile fills its container edge-to-edge — perfect for the
 * "fills the whole screen" feel the user requested.  The previous
 * emoji-on-gradient system is gone; legacy profiles whose avatar
 * id doesn't match a current entry fall back to the first avatar
 * via `getAvatar`.
 */

/* DiceBear PNG endpoint builder.  Pin to v9.x and request a
   reasonably high resolution (256) so the tile stays sharp even
   when the picker renders the avatar at ~160 px.  All character
   portraits use radius=50 so the SVG/PNG is pre-cropped to a
   circle — eliminates a layer of CSS work on the WebView. */
const DICEBEAR = 'https://api.dicebear.com/9.x';
const dbear = (style, seed, opts = {}) => {
    const qs = new URLSearchParams({
        seed: String(seed),
        size: '256',
        radius: '50',
        backgroundType: 'gradientLinear',
        ...opts,
    }).toString();
    return `${DICEBEAR}/${style}/png?${qs}`;
};

