/* Expand seeds into avatar records.  ID schema: `<catId>-<idx>`. */
export const AVATAR_CATEGORIES = CATS.map((c) => ({
    id: c.id,
    label: c.label,
    items: c.seeds.map((s, i) => ({
        id: `${c.id}-${i + 1}`,
        src: dbear(c.style, s),
        glow: c.glow,
        seed: s,
        style: c.style,
    })),
}));

/* Flat list — used by `getAvatar(id)` and anywhere else the
   picker needs every avatar regardless of category. */
export const AVATARS = AVATAR_CATEGORIES.flatMap((c) => c.items);

/* Synthetic Kids profile avatar — friendly bear-ish smile that's
   NOT exposed in the picker (hidden=true, filtered out by
   ProfileEdit.jsx's visibleAvatars). */
const KIDS = {
    id: 'kids-default',
    src: dbear('big-smile', 'KidBear', { backgroundColor: 'ffd700,ff9a3c' }),
    glow: '#FFC857',
    seed: 'KidBear',
    style: 'big-smile',
    hidden: true,
};
AVATARS.push(KIDS);

export function getAvatar(id) {
    return AVATARS.find((a) => a.id === id) || AVATARS[0];
}

/**
 * Reusable circular avatar.  Renders a full-bleed PNG inside a
 * round container with a subtle glow that matches the avatar's
 * dominant color.  When `ring` is true (currently-selected
 * profile) we wrap the circle in a brand-blue focus ring.
 */
export function AvatarCircle({ avatarId, size = 96, ring = false }) {
    const a = getAvatar(avatarId);
    return (
        <span
            data-testid={`avatar-${avatarId}`}
            style={{
                display: 'inline-flex',
                position: 'relative',
                width: size,
                height: size,
                borderRadius: '50%',
                overflow: 'hidden',
                // Soft tinted plate behind the PNG so the SVG
                // background doesn't read as a flat square if
                // DiceBear ever returns a transparent corner.
                background: `radial-gradient(circle at 30% 30%, ${a.glow}33, rgba(0,0,0,0.6))`,
                boxShadow: ring
                    ? `0 0 0 3px var(--vesper-blue-bright), 0 0 32px 4px ${a.glow}66`
                    : `0 14px 36px -10px ${a.glow}88`,
                userSelect: 'none',
            }}
        >
            <img
                src={a.src}
                alt=""
                loading="lazy"
                decoding="async"
                draggable={false}
                style={{
                    position: 'absolute',
                    inset: 0,
                    width: '100%',
                    height: '100%',
                    objectFit: 'cover',
                    display: 'block',
                    pointerEvents: 'none',
                }}
                onError={(e) => {
                    // If DiceBear is unreachable, fall back to a
                    // tinted initial so the tile stays visually
                    // intact rather than collapsing to a broken
                    // image icon.
                    const el = e.currentTarget;
                    el.style.visibility = 'hidden';
                }}
            />
        </span>
    );
}
